args.sparql:
SELECT ?item ?itemLabel
WHERE {
  ?item wdt:P31 wd:Q13442814 .
  ?item rdfs:label ?itemLabel .
  FILTER (LANG(?itemLabel) = "en") .
}

SELECT ?mission ?missionLabel WHERE {
  ?mission wdt:P31 wd:Q783637 .
  ?mission wdt:P921 wd:Q18508 .
  ?mission rdfs:label ?missionLabel .
  FILTER (LANG(?missionLabel) = "en")
}

SELECT ?project ?projectLabel WHERE {
  ?project rdfs:label ?projectLabel .
  FILTER (LANG(?projectLabel) = "en") .
  FILTER (CONTAINS(LCASE(?projectLabel), "exoplanet")) .
  FILTER (CONTAINS(LCASE(?projectLabel), "search") || CONTAINS(LCASE(?projectLabel), "survey")) .
}
